const input = $input.first().json;
const scriptId = input.scriptId ?? 'cooking_test';
const recipe = input.recipe ?? input; // fallback if passed flat

const ingredientsList = (recipe.ingredients ?? []).join('\n- ');
const stepsList = (recipe.steps ?? []).map((s, i) => `${i+1}. ${s}`).join('\n');

const recipeText = `Rezeptname: ${recipe.name ?? 'Unbekannt'}
Portionen: ${recipe.servings ?? 2}
Vorbereitungszeit: ${recipe.prepTime ?? 'unbekannt'}
Kochzeit: ${recipe.cookTime ?? 'unbekannt'}

ZUTATEN:
- ${ingredientsList}

ZUBEREITUNG:
${stepsList}`;

return [{ json: { scriptId, recipe_name: recipe.name ?? 'Unbekannt', recipe_text: recipeText } }];

const raw = $input.first().json.output ?? '';
let parsed;

// Extract JSON from agent output
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch(e) {
  return [{ json: { error: 'JSON parse failed', raw_output: raw.slice(0, 500) } }];
}

// Validate and fix total_duration_seconds
const clips = parsed.clips ?? [];
const actualTotal = clips.reduce((sum, c) => sum + (Number(c.duration_seconds) || 0), 0);

// Inject scriptId and fix duration
const scriptId = $('Prepare Recipe Input').first().json.scriptId;
parsed.total_duration_seconds = actualTotal;
parsed.scriptId = scriptId;

// Validation warnings
const warnings = [];
if (actualTotal < 60) warnings.push(`total_duration ${actualTotal}s is below 60s minimum`);
if (actualTotal > 90) warnings.push(`total_duration ${actualTotal}s exceeds 90s target`);
if (!clips.some(c => c.act === 'hook')) warnings.push('missing hook act');
if (!clips.some(c => c.act === 'beauty shots')) warnings.push('missing beauty shots act');

parsed._validation = { warnings, clip_count: clips.length, actual_total_seconds: actualTotal };

return [{ json: parsed }];
